/// Static completion candidates extracted from pinned web-language packages.
pub fn generated_completion_words(language: &str) -> &'static [&'static str] {
    match language {
        "javascript" => JAVASCRIPT,
        "typescript" | "tsx" => TYPESCRIPT,
        "html" => HTML,
        "css" | "scss" => CSS,
        "sql" => SQL,
        _ => &[],
    }
}
